fn generate_source_map<T>(input_data: Vec<(String, T)>) -> HashMap<String, String> where T: std::fmt::Debug {
    let mut map = HashMap::new();
    for (key, value) in input_data { 
        println!("Processing key: {}", key);
        match stringify!(T) {
            "i32" => { 
                map.insert(format!("{}", key), format!("Source for integer value."));
            },
            _ => { 
                map.insert(format!("{}", key), format!("Unknown source marker for type {:?}.", value));
            }
        }
    }
    map
}

fn main() {
    let data: Vec<(String, i32)> = vec![ 
        ("main_entry".to_string(), 10),
        ("helper_call".to_string(), 5)
    ];

    let source_map = generate_source_map(data);

    for (key, location) in &source_map {
        println!("Found mapping for \"{}\": \"{}\"", key, location);
    }
}

use std::mem::MaybeUninit;

struct PeripheralStatusBlock {
    status_register: u32,
    gpio_output: u32,
}

impl PeripheralStatusBlock {
    fn new(base_address: usize) -> Self {
        unsafe {
            let status_ptr = base_address as *const u32;
            let gpio_ptr = (base_address + 4) as *const u32;

            Self {
                status_register: std::ptr::read(status_ptr),
                gpio_output: std::ptr::read(gpio_ptr),
            }
        }
    }

    fn read_interrupt_data(&self) -> u32 {
        self.status_register & 0xFF
    }

    fn check_gpio_line(&self, line: u8) -> bool {
        (self.gpio_output & (1 << line)) != 0
    }

    fn process_data(&self, interrupt_count: u32) -> u32 {
        let data = self.read_interrupt_data();
        if self.check_gpio_line(5) {
            (data & 0xFF) | (interrupt_count << 8)
        } else {
            data
        }
    }
}

fn main() {
    let base_address = 0x40001000;
    let peripheral = PeripheralStatusBlock::new(base_address);

    let result_a = peripheral.process_data(10);
    println!("Processed Data A: {}", result_a);

    let mut buffer: [u8; 4] = [0; 4];
    unsafe {
        std::ptr::write(buffer.as_mut_ptr() as *mut u32, 0xDEADBEEF);
    }

    let result_b = peripheral.process_data(1);
    println!("Processed Data B: {}", result_b);
}

