struct HandshakeMessage<T: Send + 'static> {
    sequence_number: u32,
    payload: T,
}

impl<T: std::marker::Send> Display for HandshakeMessage<T> {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "HandshakeMessage {{ sequence_number: {}, payload_type_is_empty }}", self.sequence_number)
    }
}

struct Tls13Context<T> where T: std::marker::Send + 'static {
    last_message: Option<HandshakeMessage<T>>
}

fn main() {
    let mut context = Tls13Context::<EmptyMarker> { last_message: None };
    println!("Initialized TLS Context using Empty Marker.");

    let msg1 = HandshakeMessage { sequence_number: 0, payload: EmptyMarker::default() };
    context.last_message = Some(msg1);

    match context.last_message {
        Some(message) => println!("Successfully recorded message: {}", message),
        None => println!("No messages recorded.")
    }
}
